import{_ as e,o as a,c as p,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"大树守卫","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/6.套装/大树守卫.md","filePath":"4.资源分区/7.物品与装备/6.套装/大树守卫.md"}'),s={name:"4.资源分区/7.物品与装备/6.套装/大树守卫.md"};function o(d,b,l,_,i,c){return a(),p("div",null,[...b[0]||(b[0]=[r("h1",{id:"大树守卫",tabindex:"-1"},[t("大树守卫 "),r("a",{class:"header-anchor",href:"#大树守卫","aria-label":'Permalink to "大树守卫"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风028")])])],-1),n('<h1 id="大树守卫-1" tabindex="-1">大树守卫 <a class="header-anchor" href="#大树守卫-1" aria-label="Permalink to &quot;大树守卫&quot;">​</a></h1><p>大树守卫</p><p>介绍：《艾尔登法环》世界观中，以侍奉黄金树为己任的重装骑士“大树守卫”所穿着的装备，通体有着和黄金树一样耀眼的光泽，印证着他们信念的坚定。金甲的骑士纵马冲杀，扑灭了无数对于黄金树怀抱着恶意的欲望的火焰。</p><p>大树守卫头盔<br> 价格：C+1000<br> 分类：奇物（头盔）<br> 描述：侍奉黄金树的重装骑士──大树守卫的黄金制头盔。头盔上大上一圈的黄金树冠顶饰，只有少部分的人能够配戴。<br> 这是一件能够为穿戴者提供5点盔甲防御的头盔。如常占据头盔部位。<br> 【黄金树守护】:大树守卫的头盔上以黄金树的树冠装饰，坚定的黄金树信仰在与敌人的作战中保护着他们。只要穿戴这件头盔的人在学识上持有“黄金树信仰”专业，那么他就会在三豁免上获得传奇决心*2点神圣加值。</p><p>大树守卫铠甲<br> 价格：C+1000<br> 分类：盔甲（重甲）<br> 描述：侍奉黄金树的重装骑士──大树守卫的黄金制铠甲。披着大树图案的斗篷。厚重得令人吃惊，连带着也相当坚固。还残留着过去获得的赐福。<br> 这是一件能够为穿戴者提供12点盔甲防御的重甲，具有5点盔甲减值以及基于盔甲防御的【坚韧】效果。<br> 【黄金树捍卫】:大树守卫的铠甲通体呈现略显岁月痕迹的黄金色泽，其上雕刻着大树的形象，厚重的甲片与黄金树的赐福一起，给予了他们捍卫黄金树的力量。只要你在学识上具有“专业：黄金树信仰”，那么你的这件重甲的盔甲防御就提升等同【决心】一半的数值。</p><p>大树守卫臂甲<br> 价格：C+1000<br> 分类：奇物（臂甲）<br> 描述：侍奉黄金树的重装骑士──大树守卫的黄金制臂甲。黄金树的枝干与根系的形状在其上构成了复杂的花纹，穿戴着臂甲的守卫持用着沉重的武器，为了那散发着金色光辉，将交界地普照的崇高存在而战。<br> 这是一件能够为穿戴者提供5点盔甲防御的臂甲。如常占据手腕部位。<br> 【黄金树勇力】:大树守卫的臂甲不仅厚重，而且附加了黄金树的赐福。你在进行白刃攻击时，可以使用“专业：黄金树信仰”代替“专业：武学掌握”。<br> 当你具有5级的“专业：黄金树信仰”时，你以长杆武器进行的攻击加骰等级提升一级，至多为8加骰。</p><p>大树守卫腿甲<br> 价格：C+1000<br> 分类：奇物（腿甲）<br> 描述：侍奉黄金树的重装骑士──大树守卫的黄金制腿甲。黄金树的枝干与根系的形状在其上构成了复杂的花纹，穿戴着臂甲的守卫持用着沉重的武器，为了那散发着金色光辉，将交界地普照的崇高存在而战。<br> 这是一件能够为穿戴者提供5点盔甲防御的腿甲。并且由于这个装备对下肢的完全包裹，它将占据鞋袜部位。<br> 【黄金树屹立】:大树守卫的腿甲之上，拥有宛如叶脉一般的纹路，承载着来自于黄金树的力量。你即使生命池被严重伤害填满，也不会昏迷。<br> 当你生命值不具有完好生命值并且你起码具有5级的“专业：黄金树信仰”时，你额外具有2点基于盔甲防御的全伤害吸收。</p><p>黄金戟<br> 价格：C+2500<br> 分类：戟<br> 描述：以黄金制成的厚重戟。人称“大树守卫”的重装骑士持有的武器。具有圣属性攻击力。重量颇重，但威力也不错的武器，但以普通人的力气可能难以挥舞。<br> 这是一柄具有12L武器伤害的戟，具有【长柄】，【双手】，【格挡2】。这柄武器由于其形制，在攻击时可以选择造成穿刺伤害，也可以选择造成挥砍伤害，不过一次攻击只能选择其中一种伤害类型获得。<br> 【圣伤害】:你每在决心上具有2点附加成功，就在以本武器进行攻击时额外造成1点正能量伤害。<br> 【黄金树庇佑】：以一个移动动作，你将武器指向天空，发誓为黄金树而战，你在攻击上具有6点神圣加值，并且在防御上额外获得6点神圣防御，持续一个场景。<br> 因为这个效果隶属于艾尔登法环世界观下的战技，所以褪色者血统中所记述的适用于战灰的AP，也可以被应用于发动这个效果。</p><p>黄金树大盾<br> 价格：C+1000<br> 分类：重盾<br> 描述：用黄金制成的厚重大盾。人称“大树守卫”的重装骑士持有的武器。执行过古老守护的祷告。此为所有黄金树的守护者们奉为圭臬，犹如城墙般的盾牌。<br> 这是一柄具有6L武器伤害的重盾，造成钝击伤害，具有【双手】，【格挡10】。当你一只手握持黄金戟，另一只手持有这个盾牌时，黄金戟将不再具有【格挡2】，取而代之，这面盾牌的【格挡】的数值将提升2点。<br> 【黄金树奉还】：这个效果只能在应对造成能量伤害的远程攻击而发动招架时才能使用，消耗1点意志力，你针对这次攻击额外具有6点全能量抗力。并且这次攻击的能量会被积攒在黄金树大盾之中，你可以选择在下一次你的行动轮中，消耗一个标准动作，释放能量进行一次攻击，这次攻击造成正能量伤害，具有【预设】特性，预设的攻击为49DP+6附加。</p><p>大树守卫战马<br> 价格：C+1000<br> 分类：载具（生物类载具/轻型载具）<br> 描述：体格庞大的战马，拥有出色的力量与体魄，可以背负身着重装的大树守卫。<br> 基本能力值<br> 智力 6<br> 感知 9<br> 决心 9</p><p>力量 11<br> 敏捷 11<br> 耐力 9</p><p>风度 6<br> 操控 6<br> 沉着 6</p><p>技能<br> 知识1 黄金树信仰1<br> 器用1<br> 手艺1<br> 专注5-意志4</p><p>运动8-反射8<br> 生存8-强韧8，求生5<br> 射击1<br> 武技5-蹄5</p><p>洞察5-侦察5<br> 隐秘5-潜藏5<br> 表达1<br> 社交1</p><p>衍生属性值<br> ▓▓▓▓衍生属性值<br> 相貌:3<br> ▓体积 7<br> ▓速度35 （力量【11】+敏捷【11】+体积【7】+每1点敏捷上的附加获得3移动速度）+体格庞大【35】=70<br> ▓先攻2rd10+17 （敏捷【11】+沉着【6】）<br> ▓防御 8+2（敏捷感知的平均值【8】+较高者的附加成功【2】）<br> ▓生命值17 （耐力【9】+体积【7】+耐力附加【1 】×5）<br> ▓意志力池20 （决心【9】+沉着【9】+决心附加【1 】×2）<br> ▓意志19+3 （决心【9】+专注5+意志【4】）+传风1<br> ▓反射28+4 （敏捷【11】+运动8+反射【8】）+传风1<br> ▓强韧25+3 （耐力【9】+生存8+强韧【8】）+传风1<br> ▓侦查 20+2（感知【9】+洞察5+侦查【5】）+传风1<br> ▓敏感范围200 （感知【9】*20米+感知上的附加成功【1 】*20米）<br> 攻击预设：<br> 蹄击：力量11+武技5+蹄5+武器伤害3+传奇力2+传奇风1＝27+6</p><p>载具特性：<br> 【体格庞大】：为了能够承载身着宛如城墙一般的护甲的大树守卫，守卫战马的体型相较于寻常马匹更为庞大。守卫战马的体积提升2点。并且由于体格更为强悍带来的爆发力，守卫战马的速度提升35米，并且全身视为3L的天生武器。<br> 【黄金树同心】：黄金树赐予你与坐骑心意相通的能力，这也是为什么所有的大树守卫在驱使自身的坐骑的时候，都那般灵活，做出各种夸张动作的原因。<br> 若你具有至少5级的【黄金树信仰】专业，当大树守卫战马在被你骑乘状态下受到攻击时，你可以花费一个反射动作打断性地为其提供全遮蔽。</p><p>【协同攻击】：守卫战马能够与大树守卫一同做出威力惊人的攻击，或者是依托马匹的跳跃，加速，增强守卫攻击的威势。<br> 当大树守卫战马在被你骑乘时，你可以消耗一个迅捷动作，操纵马匹，进行一次驾驶检定。如果这次驾驶检定成功，那么你的下一次攻击额外获得10点威猛，并且如果这个威猛在破除完对手的防御后还有剩余，则可以一比一转化为攻击上的增强加值。</p><p>大树守卫马铠<br> 价格：C+1000<br> 分类：奇物（重甲）<br> 描述：侍奉黄金树的重装骑士──大树守卫的战马所穿戴的黄金马铠。厚重的甲片紧密相连，包裹住了整个马身，除此以外，锁子甲的结构还会对战马的下盘给予保护。<br> 这是一件能够为穿戴者提供10点盔甲防御的重甲。因为其特殊的形制，只能为马匹装备。如果是体积7以下的马匹装备这个马铠，还会因为其重量而承受2点盔甲减值。<br> 【黄金树壁垒】:黄金的马铠为马匹提供了完全的包覆，使得当大树守卫与战马一同身披金甲出现在战场之上时，能够在箭雨矛丛中穿梭。<br> 当你身穿重甲，并且你的马匹也装备了大树守卫马铠时，则你或者马匹中的其中一者可以获得基于盔甲防御的【封闭4】，但是同时你和载具只能有一个享受这个效果。</p><p>套装效果：<br> 你每穿戴一件大树守卫套装下的物品（也因此大树守卫的战马与马铠不在此列），你就将承受1点不可减免，永远存在的对于“黄金树”的魅惑点数，从而使得自己在使用意志力为检定提供加值时，获得的表现加值提升1点。<br> 当你拥有了“守卫战马”与“黄金戟”时，只要你骑乘“守卫战马”你就可以沿着曲线路径进行冲锋。<br> 当你拥有了“黄金树大盾”与“大树守卫马铠”时，你额外在防御上获得基于盔甲防御的【适应】。<br> 当你拥有了所有的大树守卫套装之后，你的【黄金树庇佑】给予你的攻击上的神圣加值和防御上的神圣防御提升传奇决心*3点。如果你的“专业：黄金树信仰”到达了8级，你还可以使得【黄金树庇佑】的效果可以对半径你5米内的所有友方单位生效。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',22)])])}const m=e(s,[["render",o]]);export{f as __pageData,m as default};
